CREATE TABLE IF NOT EXISTS users ( id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, username VARCHAR(64) NOT NULL UNIQUE, email VARCHAR(128) NOT NULL, password_hash VARCHAR(255) NOT NULL, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, deleted_at DATETIME DEFAULT NULL ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS birth_charts ( id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NOT NULL, name VARCHAR(64) DEFAULT '', gender VARCHAR(8) DEFAULT 'MALE', birth_year INT NOT NULL, birth_month INT NOT NULL, birth_day INT NOT NULL, birth_hour INT DEFAULT 0, birth_minute INT DEFAULT 0, calendar_type VARCHAR(8) DEFAULT 'SOLAR', year_pillar JSON, month_pillar JSON, day_pillar JSON, hour_pillar JSON, five_elements JSON, ten_gods JSON, na_yin JSON, da_yun_start JSON, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS fortune_queries ( id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, user_id BIGINT UNSIGNED NOT NULL, chart_id BIGINT UNSIGNED NOT NULL, query_date DATE NOT NULL, day_pillar JSON, daily_fortune JSON, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE, FOREIGN KEY (chart_id) REFERENCES birth_charts(id) ON DELETE CASCADE ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS auspicious_rules ( id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, category VARCHAR(32), day_stem VARCHAR(4), day_branch VARCHAR(4), content JSON, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS activity_catalog ( id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, category VARCHAR(8), name VARCHAR(64), created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
